     1→//! Worker launcher implementation using tokio::process.
     2→//!
     3→//! This module provides the [`WorkerLauncher`] type for spawning worker processes
     4→//! in tmux sessions using configurable launcher scripts.
     5→
     6→use crate::tmux;
     7→use crate::types::{LaunchConfig, LauncherOutput, SpawnRequest, WorkerHandle};
     8→use forge_core::types::WorkerStatus;
     9→use forge_core::{ForgeError, Result};
    10→use std::collections::HashMap;
    11→use std::path::Path;
    12→use std::sync::Arc;
    13→use std::time::Duration;
    14→use tokio::process::Command;
    15→use tokio::sync::RwLock;
    16→use tokio::time::timeout;
    17→use tracing::{debug, error, info, instrument, warn};
    18→
    19→/// Worker launcher for spawning and managing worker processes.
    20→///
    21→/// The launcher uses external launcher scripts to spawn workers in tmux sessions.
    22→/// Launcher scripts must output JSON to stdout with worker information.
    23→#[derive(Debug)]
    24→pub struct WorkerLauncher {
    25→    /// Active worker handles keyed by worker ID
    26→    workers: Arc<RwLock<HashMap<String, WorkerHandle>>>,
    27→    /// Session name prefix for all workers
    28→    session_prefix: String,
    29→}
    30→
    31→impl Default for WorkerLauncher {
    32→    fn default() -> Self {
    33→        Self::new()
    34→    }
    35→}
    36→
    37→impl WorkerLauncher {
    38→    /// Create a new worker launcher.
    39→    pub fn new() -> Self {
    40→        Self {
    41→            workers: Arc::new(RwLock::new(HashMap::new())),
    42→            session_prefix: "forge-".into(),
    43→        }
    44→    }
    45→
    46→    /// Create a new worker launcher with a custom session prefix.
    47→    pub fn with_prefix(prefix: impl Into<String>) -> Self {
    48→        Self {
    49→            workers: Arc::new(RwLock::new(HashMap::new())),
    50→            session_prefix: prefix.into(),
    51→        }
    52→    }
    53→
    54→    /// Spawn a new worker using the provided configuration.
    55→    ///
    56→    /// This will:
    57→    /// 1. Validate the launcher script exists and is executable
    58→    /// 2. Execute the launcher script with appropriate environment
    59→    /// 3. Parse the JSON output to get PID and session info
    60→    /// 4. Create a WorkerHandle and track it
    61→    #[instrument(level = "info", skip(self), fields(worker_id = %request.worker_id, model = %request.config.model))]
    62→    pub async fn spawn(&self, request: SpawnRequest) -> Result<WorkerHandle> {
    63→        let config = &request.config;
    64→        let worker_id = &request.worker_id;
    65→
    66→        // Validate launcher exists
    67→        self.validate_launcher(&config.launcher_path).await?;
    68→
    69→        info!(
    70→            "Spawning worker {} with model {} in {}",
    71→            worker_id,
    72→            config.model,
    73→            config.workspace.display()
    74→        );
    75→
    76→        // Check if session already exists and kill it
    77→        let session_name = format!("{}{}", self.session_prefix, config.session_name);
    78→        if tmux::session_exists(&session_name).await? {
    79→            warn!("Session {} already exists, killing it", session_name);
    80→            tmux::kill_session(&session_name).await?;
    81→        }
    82→
    83→        // Execute the launcher script
    84→        let output = self
    85→            .execute_launcher(worker_id, config, &session_name)
    86→            .await?;
    87→
    88→        // Parse launcher output
    89→        let launcher_output = self.parse_launcher_output(worker_id, &output).await?;
    90→
    91→        // Validate the launcher succeeded
    92→        if !launcher_output.is_success() {
    93→            return Err(ForgeError::LauncherExecution {
    94→                model: config.model.clone(),
    95→                message: launcher_output
    96→                    .error
    97→                    .unwrap_or_else(|| "Unknown launcher error".into()),
    98→            });
    99→        }
   100→
   101→        // Verify the session was created
   102→        if !tmux::session_exists(&launcher_output.session).await? {
   103→            return Err(ForgeError::WorkerSpawn {
   104→                worker_id: worker_id.clone(),
   105→                message: format!(
   106→                    "Launcher claimed to create session '{}' but it doesn't exist",
   107→                    launcher_output.session
   108→                ),
   109→            });
   110→        }
   111→
   112→        // Create worker handle with optional bead assignment
   113→        let mut handle = WorkerHandle::new(
   114→            worker_id.clone(),
   115→            launcher_output.pid,
   116→            launcher_output.session.clone(),
   117→            config.launcher_path.clone(),
   118→            if launcher_output.model.is_empty() {
   119→                config.model.clone()
   120→            } else {
   121→                launcher_output.model.clone()
   122→            },
   123→            config.tier,
   124→            config.workspace.clone(),
   125→        );
   126→
   127→        // Add bead assignment if present in launcher output or config
   128→        if let Some(ref bead_id) = launcher_output.bead_id {
   129→            let bead_title = launcher_output
   130→                .bead_title
   131→                .clone()
   132→                .unwrap_or_else(|| bead_id.clone());
   133→            handle = handle.with_bead(bead_id.clone(), bead_title);
   134→        } else if let Some(ref bead_id) = config.bead_id {
   135→            handle = handle.with_bead(bead_id.clone(), bead_id.clone());
   136→        }
   137→
   138→        // Store the handle
   139→        {
   140→            let mut workers = self.workers.write().await;
   141→            workers.insert(worker_id.clone(), handle.clone());
   142→        }
   143→
   144→        info!(
   145→            "Worker {} spawned successfully (PID: {}, session: {})",
   146→            worker_id, launcher_output.pid, launcher_output.session
   147→        );
   148→
   149→        Ok(handle)
   150→    }
   151→
   152→    /// Validate that a launcher script exists and is executable.
   153→    async fn validate_launcher(&self, path: &Path) -> Result<()> {
   154→        if !path.exists() {
   155→            return Err(ForgeError::launcher_not_found(path));
   156→        }
   157→
   158→        // Check if executable on Unix
   159→        #[cfg(unix)]
   160→        {
   161→            use std::os::unix::fs::PermissionsExt;
   162→            let metadata = tokio::fs::metadata(path)
   163→                .await
   164→                .map_err(|e| ForgeError::io("checking launcher permissions", path, e))?;
   165→            let permissions = metadata.permissions();
   166→            if permissions.mode() & 0o111 == 0 {
   167→                return Err(ForgeError::LauncherNotExecutable { path: path.into() });
   168→            }
   169→        }
   170→
   171→        debug!("Launcher validated: {}", path.display());
   172→        Ok(())
   173→    }
   174→
   175→    /// Execute the launcher script and capture output.
   176→    async fn execute_launcher(
   177→        &self,
   178→        worker_id: &str,
   179→        config: &LaunchConfig,
   180→        session_name: &str,
   181→    ) -> Result<String> {
   182→        let mut cmd = Command::new(&config.launcher_path);
   183→
   184→        // Pass standard arguments
   185→        cmd.arg(format!("--model={}", config.model))
   186→            .arg(format!("--workspace={}", config.workspace.display()))
   187→            .arg(format!("--session-name={}", session_name));
   188→
   189→        // Pass bead-ref if we have a bead assignment (bead-aware launcher protocol)
   190→        if let Some(ref bead_id) = config.bead_id {
   191→            cmd.arg(format!("--bead-ref={}", bead_id));
   192→            debug!("Launching bead-aware worker for bead: {}", bead_id);
   193→        }
   194→
   195→        // Set working directory
   196→        cmd.current_dir(&config.workspace);
   197→
   198→        // Set environment variables
   199→        cmd.env("FORGE_WORKER_ID", worker_id);
   200→        cmd.env("FORGE_SESSION", session_name);
   201→        cmd.env("FORGE_MODEL", &config.model);
   202→        cmd.env("FORGE_WORKSPACE", &config.workspace);
   203→
   204→        for (key, value) in &config.env {
   205→            cmd.env(key, value);
   206→        }
   207→
   208→        debug!("Executing launcher: {}", config.launcher_path.display());
   209→
   210→        // Execute with timeout
   211→        let timeout_duration = Duration::from_secs(config.timeout_secs);
   212→        let result = timeout(timeout_duration, cmd.output()).await;
   213→
   214→        match result {
   215→            Ok(Ok(output)) => {
   216→                if !output.status.success() {
   217→                    let stderr = String::from_utf8_lossy(&output.stderr);
   218→                    let stdout = String::from_utf8_lossy(&output.stdout);
   219→                    error!(
   220→                        "Launcher failed with status {}: stdout={}, stderr={}",
   221→                        output.status, stdout, stderr
   222→                    );
